import React from "react";

export default function DecisionCard({
  decision,
  confidence,
  reasoning,
  asset,
  finalAction,
  agentVotes
}) {
  return (
    <div className="bg-card rounded-xl p-5 shadow-sm border border-slate-200">
      <h2 className="text-lg font-semibold mb-3">AI Decision</h2>
      <p className="text-sm mb-1">
        Decision: <span className="font-bold">{decision || "-"} {asset ? asset.toUpperCase() : ""}</span>
      </p>
      <p className="text-sm mb-1">
        Confidence: <span className="font-medium">{typeof confidence === "number" ? confidence.toFixed(2) : "-"}</span>
      </p>
      <p className="text-sm mb-2">
        Final Action: <span className="font-medium">{finalAction || decision || "-"}</span>
      </p>
      <p className="text-sm text-slate-600">Reason: {reasoning || "No reasoning available"}</p>
      <div className="mt-4 space-y-2">
        <h3 className="text-sm font-semibold">Agent Votes</h3>
        {(agentVotes || []).length === 0 ? (
          <p className="text-xs text-slate-500">No agent votes available.</p>
        ) : (
          agentVotes.map((vote) => (
            <div
              key={vote.agent}
              className="rounded-lg border border-slate-100 bg-slate-50 px-3 py-2 text-xs"
            >
              <p className="font-semibold">{vote.agent}</p>
              <p>
                {vote.action} | confidence{" "}
                {typeof vote.confidence === "number" ? vote.confidence.toFixed(2) : "-"}
              </p>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
